import React from 'react';
import { HomepageBanner, HomepageCallout } from 'gatsby-theme-carbon';
import HomepageTemplate from 'gatsby-theme-carbon/src/templates/Homepage';
import { calloutLink } from './Homepage.module.scss';
import BG from './BG.jpg';

const FirstLeftText = () => {
  const paragraphStyle = {
    fontSize: 'larger',
    color: '#ffffff',
    fontWeight: 'light',
  };
  return <p style={paragraphStyle}>About This Site</p>;
};

const FirstRightText = () => {
  const paragraphStyle = {
    color: '#ffffff',
    fontSize: '20px',
  };
  return (
    <p style={paragraphStyle}>
      This website is designed to document my daily life, including study notes,
      tool usage, entertainment, various random thoughts and ideas.
    </p>
  );
};

const SecondLeftText = () => {
  const paragraphStyle = {
    fontSize: 'larger',
    color: '#ffffff',
  };
  return <p style={paragraphStyle}>About Myself</p>;
};

const SecondRightText = () => {
  const paragraphStyle = {
    fontSize: '20px',
    fontWeight: 'light',
  };
  return (
    <p style={paragraphStyle}>
      Developer, fish keeper, city skylines player Enthusiastic in dev-ops,
      kubernetes, storage management solution C++ / C# lover, LLM amateur
      beginner.
      <a className={calloutLink} href="/todo">
        More About Me
      </a>
    </p>
  );
};

const BannerText = () => {
  const paragraphStyle = {
    fontSize: '40px',
    fontWeight: 'bold',
    color: '#1B2CC1',
    transform: 'translateY(-2rem)',
  };
  return <p style={paragraphStyle}>BLUEPHOENIIIX</p>;
};

const customProps = {
  Banner: <HomepageBanner renderText={BannerText} image={BG} />,
  FirstCallout: (
    <HomepageCallout
      backgroundColor="#030303"
      color="#ABD2FA"
      leftText={FirstLeftText}
      rightText={FirstRightText}
    />
  ),
  SecondCallout: (
    <HomepageCallout
      leftText={SecondLeftText}
      rightText={SecondRightText}
      color="white"
      backgroundColor="#061f80"
    />
  ),
};

// spreading the original props gives us props.children (mdx content)
function ShadowedHomepage(props) {
  return <HomepageTemplate {...props} {...customProps} />;
}

export default ShadowedHomepage;
